#include <stdio.h>
#include <openssl/bn.h>

void printBN(char *msg, BIGNUM *a)
{
    char *number_str = BN_bn2hex(a);
    printf("%s %s\n", msg, number_str);
    OPENSSL_free(number_str);
}

int main()
{
    BN_CTX *ctx = BN_CTX_new();

    BIGNUM *n = BN_new();
    BIGNUM *e = BN_new();
    BIGNUM *signature = BN_new();
    BIGNUM *result = BN_new();

    /* chave pública da CA */
    BN_hex2bn(&n, "");
    BN_hex2bn(&e, "10001");

    /* assinatura */
    BN_hex2bn(&signature, "");

    /* RSA verification */
    BN_mod_exp(result, signature, e, n, ctx);

    printBN("Assinatura decodificada =", result);

    return 0;
}